UPDATE public.questions SET
  stimulus_text = 'In her essay on urban soundscapes, writer 59 contends that city planners should classify chronic noise pollution as a public-health hazard, citing longitudinal studies linking traffic noise to elevated cortisol, fragmented sleep, and diminished cognitive performance among residents. She describes neighborhoods where sirens, construction, and highway hum overlap for eighteen hours daily, leaving inhabitants with interrupted rest even when particulate counts meet regulatory thresholds. Community interviews quoted in the essay repeatedly mention difficulty concentrating at work, heightened irritability at home, and reluctance to open windows despite heat. The writer contrasts cosmetic beautification projects—planters, murals, and repainted facades—with measurable acoustic interventions such as berms, low-noise pavement, delivery-time restrictions, and targeted speed reductions. She acknowledges that absolute silence is unattainable in dense cities, yet insists that reducing predictable high-decibel spikes could yield health benefits comparable to modest gains in accessible green space. The essay concludes that sound belongs in municipal planning budgets alongside air quality and light pollution.',
  question_text = 'According to the passage, which statement is most strongly supported by the text?',
  stimulus_type = 'passage',
  options = '[{"id":"A","text":"The passage establishes that sustained parrotfish grazing suppresses macroalgal proliferation, linking herbivory to measurable recruitment outcomes across monitored sites.","is_correct":true,"explanation":"The passage explicitly ties sustained parrotfish grazing suppresses macroalgal proliferation to reef health through comparative site data rather than speculative claims."},{"id":"B","text":"Once macroalgae dominate a reef, coral larvae can never attach to any surface regardless of subsequent grazing pressure.","is_correct":false,"explanation":"The passage describes recovery mechanisms and does not claim permanent loss once algae appear; grazing can restore bare rock."},{"id":"C","text":"The authors dismiss empirical field surveys in favor of anecdotal reports from recreational divers who visit the sites.","is_correct":false,"explanation":"The passage cites transects, chemical assays, and follow-up surveys—methods inconsistent with rejecting scientific inquiry."},{"id":"D","text":"Temperature and salinity fluctuations alone explain every decline in coral recruitment documented in the longitudinal study.","is_correct":false,"explanation":"The passage states recruitment declined even when temperature and salinity remained stable, implicating grazing rather than water chemistry alone."}]'::jsonb,
  correct_answer = 'A',
